SELECT etichettecampioni.*, [NavisionEan-step0].[Cross-Reference No_] AS EANFound, [NavisionEan-step0-UPC].[Cross-Reference No_] AS UPCFound, [Variable Code_1].Description AS SizeDesc, [Variable Code].Description AS ColorDescription, Item_1.[Description 2]
FROM (((((etichettecampioni INNER JOIN Item ON (etichettecampioni.SIZE = Item.[Variable Code 02]) AND (etichettecampioni.[BRIDGE COLOR CODE] = Item.[Variable Code 01]) AND (etichettecampioni.[BRIDGE STYLE CODE] = Item.[Model Item No_])) LEFT JOIN [NavisionEan-step0] ON Item.No_ = [NavisionEan-step0].[Item No_]) LEFT JOIN [NavisionEan-step0-UPC] ON Item.No_ = [NavisionEan-step0-UPC].[Item No_]) INNER JOIN [Variable Code] ON (Item.[Variable Code 01] = [Variable Code].[Variable Code]) AND (Item.[Variable Group 01] = [Variable Code].[Variable Group])) INNER JOIN [Variable Code] AS [Variable Code_1] ON (Item.[Variable Code 02] = [Variable Code_1].[Variable Code]) AND (Item.[Variable Group 02] = [Variable Code_1].[Variable Group])) INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_;

